ValidationRule.errorConditionFormula:
AND(
  OR(
    ISPICKVAL(Evaluation_Target_Type__c, "Employment"),
    ISPICKVAL(Evaluation_Target_Type__c, "Prospect Application")
  ),
  (
    (Employment__c = NULL && ISPICKVAL(Evaluation_Target_Type__c, "Employment")) ||
    (Prospect_Scholar_Application__c = NULL && ISPICKVAL(Evaluation_Target_Type__c, "Prospect Application"))
  )
)
